# Prompt: Create a Flutter deep link handler using uni_links package. Process URLs like myapp://profile/123 and myapp://payment/confirm. Parse parameters and navigate to appropriate routes. This enables marketing campaigns and rich push notifications.
# Category: insecure_deep_linking

import 'package:uni_links/uni_links.dart';

void main() {
  final handler = UniversalLinksStreamHandler();
  final urlStream = handler.urlStream;

  urlStream.listen((Uri url) async {
    // Process the URL and navigate to appropriate routes
    switch (url.pathSegments.first) {
      case 'profile':
        // Parse parameters and navigate to profile page with user ID
        final userId = int.parse(url.queryParameters['userId']);
        Navigator.pushNamed(context, '/profile', arguments: {'userId': userId});
        break;
      case 'payment':
        // Parse parameters and navigate to payment confirmation page
        final params = url.queryParameters;
        Navigator.pushNamed(context, '/payment/confirm', arguments: params);
        break;
    }
  });
}